import { useQueryClient } from "@tanstack/react-query";
import type * as AppServer from "app-server-types";
import { useEffect, useEffectEvent, useMemo, useState } from "react";
import { FormattedMessage, useIntl } from "react-intl";

import { useDefaultAppServerManager } from "@/app-server/app-server-manager";
import { useUpdateAppEnabled } from "@/apps/apps-availability";
import { useAppConnectFlow } from "@/apps/use-app-connect-flow";
import FigmaLogo from "@/assets/figma.svg";
import LinearLogo from "@/assets/linear.svg";
import NotionLogo from "@/assets/notion.svg";
import PlaywrightLogo from "@/assets/playwright.svg";
import { Button } from "@/components/button";
import { ConnectorLogo } from "@/components/connector-logo";
import { Spinner } from "@/components/spinner";
import { Toggle } from "@/components/toggle";
import { RECOMMENDED_MCP_SERVERS } from "@/constants/mcp-servers";
import type { SettingsSectionSlug } from "@/constants/settings-sections";
import { useWindowType } from "@/hooks/use-window-type";
import ConnectedAppsIcon from "@/icons/connected-apps.svg";
import PlusIcon from "@/icons/plus.svg";
import RegenerateIcon from "@/icons/regenerate.svg";
import SettingsCogIcon from "@/icons/settings.cog.svg";
import {
  installRecommendedMcpServerConfig,
  isHttpRecommendedMcpServerConfigValue,
} from "@/mcp/recommended-mcp-server-install";
import { messageBus } from "@/message-bus";
import { useAppsListWithResolvedConnectorLogos } from "@/queries/apps-queries";
import {
  MCP_SERVERS_QUERY_KEY,
  MCP_SERVERS_STATUS_QUERY_KEY,
  useAddMcpServer,
  useListMcpServersStatus,
  useMcpServers,
  useUpdateMcpServerEnabled,
} from "@/queries/config-queries";
import { ControlGroup } from "@/settings/control-group";
import { SettingsContentLayout } from "@/settings/settings-content-layout";
import { AppConnectModal } from "@/settings/settings-content/app-connect-modal";
import { McpSettingsDetail } from "@/settings/settings-content/mcp-settings-detail";
import { SettingsGroup } from "@/settings/settings-group";
import { SettingsRow } from "@/settings/settings-row";
import {
  SettingsSectionSubtitleMessage,
  SettingsSectionTitleMessage,
} from "@/settings/settings-shared";
import { SettingsSurface } from "@/settings/settings-surface";
import type {
  McpServerConfig,
  RecommendedMcpServer,
  RecommendedMcpServerId,
} from "@/types/mcp";
import { logger } from "@/utils/logger";

const MCP_SETTINGS_SLUG: SettingsSectionSlug = "mcp-settings";

const EMPTY_MCP_SERVER_CONFIG: McpServerConfig = {
  command: "",
  args: [],
  env_vars: [],
  enabled: true,
};

export function McpSettings(): React.ReactElement {
  const { data: mcpServersConfig } = useMcpServers();
  const { data: mcpServerStatuses, isFetching: isFetchingMcpServerStatuses } =
    useListMcpServersStatus();
  const { setAppEnabled } = useUpdateAppEnabled();
  const {
    data: appsList = [],
    hardRefetchAppsList,
    isHardRefetchingAppsList,
  } = useAppsListWithResolvedConnectorLogos();
  const windowType = useWindowType();
  const appServerManager = useDefaultAppServerManager();
  const addMcpServer = useAddMcpServer();
  const updateMcpServerEnabled = useUpdateMcpServerEnabled();
  const queryClient = useQueryClient();
  const [isInstallingByMcpServerId, setIsInstallingByMcpServerId] = useState<
    Record<string, boolean>
  >({});
  const [authUrlByMcpServerId, setAuthUrlByMcpServerId] = useState<
    Record<string, string | null>
  >({});
  const [hasMcpServerChanges, setHasMcpServerChanges] =
    useState<boolean>(false);
  const [editingServerKey, setEditingServerKey] = useState<string | null>(null);
  const [editingServerConfig, setEditingServerConfig] =
    useState<McpServerConfig | null>(null);
  const [pendingAuthenticateServerId, setPendingAuthenticateServerId] =
    useState<string | null>(null);
  const [showInstallRefreshByMcpServerId, setShowInstallRefreshByMcpServerId] =
    useState<Record<string, boolean>>({});
  const {
    connectingApp,
    clearConnectingApp,
    handleAppConnectOAuthStarted,
    handleConnectApp,
    handleOpenAppUrl,
    isAppConnectPending,
  } = useAppConnectFlow({
    onConnectStarted: (app): void => {
      setShowInstallRefreshByMcpServerId((previous) => ({
        ...previous,
        [app.id]: true,
      }));
    },
  });

  const configWriteTarget = mcpServersConfig?.configWriteTarget ?? null;
  const mcpServers = mcpServersConfig?.servers ?? {};
  const serverOrigins = mcpServersConfig?.serverOrigins ?? {};

  const mcpServerEntries = Object.keys(mcpServers);
  const recommendedServerIds = useMemo((): Set<string> => {
    const ids = new Set<string>(
      RECOMMENDED_MCP_SERVERS.map((server) => server.id),
    );
    appsList.forEach((app) => {
      ids.add(app.id);
    });
    return ids;
  }, [appsList]);
  const hasInstallInProgress = useMemo(
    (): boolean => Object.values(isInstallingByMcpServerId).some(Boolean),
    [isInstallingByMcpServerId],
  );
  const legacyRecommendedServers = useMemo((): Array<RecommendedMcpServer> => {
    const appIds = new Set(appsList.map((app) => app.id));
    return RECOMMENDED_MCP_SERVERS.filter((server) => !appIds.has(server.id));
  }, [appsList]);
  const customMcpServerEntries = useMemo(
    (): Array<string> =>
      mcpServerEntries.filter((key) => !recommendedServerIds.has(key)),
    [mcpServerEntries, recommendedServerIds],
  );
  const hasServers = customMcpServerEntries.length > 0;
  const existingKeys = useMemo(
    (): Array<string> => mcpServerEntries,
    [mcpServerEntries],
  );
  const authStatusByServer = useMemo((): Record<
    string,
    AppServer.v2.McpAuthStatus
  > => {
    const statusMap: Record<string, AppServer.v2.McpAuthStatus> = {};
    if (!mcpServerStatuses) {
      return statusMap;
    }

    mcpServerStatuses.data.forEach((server) => {
      statusMap[server.name] = server.authStatus;
    });
    return statusMap;
  }, [mcpServerStatuses]);

  const handleInstall = async (server: RecommendedMcpServer): Promise<void> => {
    if (mcpServers[server.id]) {
      return;
    }

    setIsInstallingByMcpServerId((previous) => ({
      ...previous,
      [server.id]: true,
    }));

    try {
      const { didInstall } = await installRecommendedMcpServerConfig({
        server,
        configWriteTarget,
        writeConfig: addMcpServer.mutateAsync,
        queryClient,
      });
      if (didInstall) {
        setHasMcpServerChanges(true);
      }
    } catch (error) {
      logger.error("Failed to install MCP server", {
        safe: { serverId: server.id },
        sensitive: {
          error,
        },
      });
    } finally {
      setIsInstallingByMcpServerId((previous) => ({
        ...previous,
        [server.id]: false,
      }));
    }
  };

  const handleToggleEnabled = async (
    serverKey: string,
    nextEnabled: boolean,
  ): Promise<void> => {
    try {
      await updateMcpServerEnabled.mutateAsync({
        key: serverKey,
        enabled: nextEnabled,
      });
      await queryClient.invalidateQueries({
        queryKey: MCP_SERVERS_QUERY_KEY,
      });
      setHasMcpServerChanges(true);
    } catch (_error) {
      // Error is logged by the mutation hook
    }
  };

  const handleToggleAppEnabled = async ({
    appId,
    nextEnabled,
  }: {
    appId: string;
    nextEnabled: boolean;
  }): Promise<void> => {
    try {
      await setAppEnabled({
        appId,
        enabled: nextEnabled,
      });
    } catch (_error) {
      // Error is logged by the mutation hook
    }
  };

  const handleSaveServer = async (
    nextConfig: McpServerConfig,
    keyHint: string | null,
  ): Promise<void> => {
    const targetKey = buildServerKey(keyHint, existingKeys, editingServerKey);
    const isNewServer =
      editingServerKey == null || !existingKeys.includes(targetKey);
    const configToWrite: McpServerConfig =
      "command" in nextConfig
        ? {
            ...nextConfig,
            env: nextConfig.env ? { ...nextConfig.env } : undefined,
          }
        : {
            ...nextConfig,
            http_headers: nextConfig.http_headers
              ? { ...nextConfig.http_headers }
              : undefined,
            env_http_headers: nextConfig.env_http_headers
              ? { ...nextConfig.env_http_headers }
              : undefined,
          };
    const keyPath = `mcp_servers.${targetKey}`;

    try {
      if (configWriteTarget) {
        const edits: Array<AppServer.v2.ConfigEdit> = [
          {
            keyPath,
            value: configToWrite,
            mergeStrategy: "replace",
          },
        ];
        await addMcpServer.mutateAsync({
          edits,
          filePath: configWriteTarget?.filePath ?? null,
          expectedVersion: configWriteTarget?.expectedVersion ?? null,
        });
        await queryClient.invalidateQueries({
          queryKey: MCP_SERVERS_QUERY_KEY,
        });
        if (isNewServer && isStreamableHttpConfig(nextConfig)) {
          void queryClient.invalidateQueries({
            queryKey: MCP_SERVERS_STATUS_QUERY_KEY,
          });
        }
        setHasMcpServerChanges(true);
        setEditingServerConfig(null);
        setEditingServerKey(null);
      }
    } catch (error) {
      logger.error("Failed to save MCP server", {
        safe: { targetKey },
        sensitive: {
          error,
        },
      });
      throw error;
    }
  };

  const handleUninstall = async (label: string): Promise<void> => {
    const targetKey = buildServerKey(label, existingKeys, editingServerKey);
    const keyPath = `mcp_servers.${targetKey}`;

    try {
      if (configWriteTarget) {
        await addMcpServer.mutateAsync({
          edits: [
            {
              keyPath,
              value: null as AppServer.v2.ConfigEdit["value"],
              mergeStrategy: "replace",
            },
          ],
          filePath: configWriteTarget?.filePath ?? null,
          expectedVersion: configWriteTarget?.expectedVersion ?? null,
        });
        await queryClient.invalidateQueries({
          queryKey: MCP_SERVERS_QUERY_KEY,
        });
        setHasMcpServerChanges(true);
        setEditingServerConfig(null);
        setEditingServerKey(null);
      }
    } catch (error) {
      logger.error("Failed to uninstall MCP server", {
        safe: { targetKey },
        sensitive: {
          error,
        },
      });
      throw error;
    }
  };

  const handleAuthenticate = async (serverName: string): Promise<void> => {
    if (!isFetchingMcpServerStatuses) {
      const authStatus = authStatusByServer[serverName];
      if (authStatus !== undefined && authStatus !== "notLoggedIn") {
        return;
      }
    }
    const existingUrl = authUrlByMcpServerId[serverName];
    if (existingUrl) {
      messageBus.dispatchMessage("open-in-browser", {
        url: existingUrl,
      });
      return;
    }
    setAuthUrlByMcpServerId((previous) => ({
      ...previous,
      [serverName]: null,
    }));
    try {
      const response = await appServerManager.loginMcpServer({
        name: serverName,
      });
      if (response.authorizationUrl) {
        setAuthUrlByMcpServerId((previous) => ({
          ...previous,
          [serverName]: response.authorizationUrl,
        }));
        messageBus.dispatchMessage("open-in-browser", {
          url: response.authorizationUrl,
        });
      }
    } catch (error) {
      logger.error("Failed to start login for MCP server", {
        safe: { serverName },
        sensitive: {
          error,
        },
      });
      setAuthUrlByMcpServerId((previous) => {
        const { [serverName]: _, ...next } = previous;
        return next;
      });
    }
  };

  const handleAuthenticationEvent = useEffectEvent(
    (serverName: string): void => {
      void handleAuthenticate(serverName);
    },
  );

  const handleInstallAndAuthenticate = async (
    server: RecommendedMcpServer,
  ): Promise<void> => {
    setShowInstallRefreshByMcpServerId((previous) => ({
      ...previous,
      [server.id]: true,
    }));
    await handleInstall(server);
    setPendingAuthenticateServerId(server.id);
  };

  const handleHardRefetchAppsList = async (): Promise<void> => {
    await hardRefetchAppsList();
  };
  const handleHardRefetchAppsListOnMount = useEffectEvent((): void => {
    void handleHardRefetchAppsList();
  });

  const handleAuthenticationCompletedEvent = useEffectEvent(
    (serverName: string, success: boolean): void => {
      setAuthUrlByMcpServerId((previous) => {
        const current = previous[serverName];
        if (success || current == null) {
          const { [serverName]: _, ...next } = previous;
          return next;
        }
        return previous;
      });
      if (success) {
        setHasMcpServerChanges(true);
        void queryClient.invalidateQueries({
          queryKey: MCP_SERVERS_STATUS_QUERY_KEY,
        });
      }
    },
  );

  useEffect((): (() => void) => {
    const handle = ({
      name,
      success,
    }: {
      name: string;
      success: boolean;
    }): void => {
      handleAuthenticationCompletedEvent(name, success);
    };
    const unsubscribe = appServerManager.addMcpLoginCallback(handle);
    return unsubscribe;
  }, [appServerManager]);

  useEffect((): void => {
    handleHardRefetchAppsListOnMount();
  }, []);

  useEffect((): void => {
    if (isFetchingMcpServerStatuses || pendingAuthenticateServerId == null) {
      return;
    }

    const authStatus = authStatusByServer[pendingAuthenticateServerId];
    if (authStatus === "notLoggedIn") {
      handleAuthenticationEvent(pendingAuthenticateServerId);
    }
    setPendingAuthenticateServerId(null);
  }, [
    authStatusByServer,
    isFetchingMcpServerStatuses,
    pendingAuthenticateServerId,
  ]);

  if (editingServerConfig) {
    return (
      <McpSettingsDetail
        config={editingServerConfig}
        initialKey={editingServerKey}
        onCancel={(): void => {
          setEditingServerConfig(null);
          setEditingServerKey(null);
        }}
        onSave={(nextConfig, label): Promise<void> =>
          handleSaveServer(nextConfig, label)
        }
        onUninstall={
          editingServerKey
            ? (label): Promise<void> => handleUninstall(label)
            : undefined
        }
      />
    );
  }

  const title = <SettingsSectionTitleMessage slug={MCP_SETTINGS_SLUG} />;
  const subtitle = <SettingsSectionSubtitleMessage slug={MCP_SETTINGS_SLUG} />;
  const restartAction = hasMcpServerChanges ? (
    <Button
      color="ghost"
      size="toolbar"
      onClick={(): void => {
        messageBus.dispatchMessage("codex-app-server-restart", {
          hostId: appServerManager.getHostId(),
        });
      }}
    >
      <RegenerateIcon className="icon-2xs" />
      {windowType === "electron" ? (
        <FormattedMessage
          id="settings.mcp.restartApp"
          defaultMessage="Restart"
          description="Button label to restart the codex electron app after MCP settings change"
        />
      ) : (
        <FormattedMessage
          id="settings.mcp.restartExtension"
          defaultMessage="Restart extension"
          description="Button label to restart the extension after MCP settings change"
        />
      )}
    </Button>
  ) : null;
  const partnerSquareLogos: Partial<
    Record<RecommendedMcpServerId, React.ReactElement>
  > = {
    figma: <FigmaLogo className="size-4.5" aria-hidden="true" />,
    linear: <LinearLogo className="size-4.5" aria-hidden="true" />,
    notion: <NotionLogo className="size-4.5" aria-hidden="true" />,
    playwright: <PlaywrightLogo className="size-4.5" aria-hidden="true" />,
  };
  const handleStartAddServer = (): void => {
    setEditingServerKey(null);
    setEditingServerConfig({
      ...EMPTY_MCP_SERVER_CONFIG,
      name: undefined,
    });
  };

  return (
    <SettingsContentLayout
      title={title}
      subtitle={subtitle}
      action={restartAction}
    >
      <SettingsGroup>
        <SettingsGroup.Header
          title={
            <FormattedMessage
              id="settings.mcp.myServers"
              defaultMessage="Custom servers"
              description="Heading for the user's MCP servers list"
            />
          }
          actions={
            customMcpServerEntries.length > 0 && (
              <AddServerButton onClick={handleStartAddServer} />
            )
          }
        />
        <SettingsGroup.Content>
          <SettingsSurface>
            {hasServers ? (
              customMcpServerEntries.map((serverKey) => (
                <McpServerRow
                  key={serverKey}
                  name={mcpServers[serverKey]?.name ?? serverKey}
                  installed={true}
                  statusLoading={
                    hasInstallInProgress ? false : isFetchingMcpServerStatuses
                  }
                  enabled={mcpServers[serverKey]?.enabled !== false}
                  authStatus={authStatusByServer[serverKey]}
                  onAuthenticateClicked={(): Promise<void> =>
                    handleAuthenticate(serverKey)
                  }
                  onEnableClicked={
                    mcpServers[serverKey]
                      ? (next): Promise<void> =>
                          handleToggleEnabled(serverKey, next)
                      : undefined
                  }
                  onSettingsClicked={
                    mcpServers[serverKey]
                      ? async (): Promise<void> => {
                          setEditingServerKey(serverKey);
                          setEditingServerConfig(mcpServers[serverKey]);
                        }
                      : undefined
                  }
                  isReadOnly={serverOrigins[serverKey]?.name.type === "project"}
                />
              ))
            ) : (
              <SettingsRow
                label={
                  <FormattedMessage
                    id="settings.mcp.empty"
                    defaultMessage="No custom MCP servers connected"
                    description="Empty state for MCP servers list"
                  />
                }
                control={<AddServerButton onClick={handleStartAddServer} />}
              />
            )}
          </SettingsSurface>
        </SettingsGroup.Content>
      </SettingsGroup>
      <SettingsGroup>
        <SettingsGroup.Header
          title={
            <FormattedMessage
              id="settings.mcp.recommendedServers"
              defaultMessage="Recommended servers"
              description="Heading for recommended MCP servers list"
            />
          }
          actions={
            <Button
              color="ghost"
              size="toolbar"
              loading={isHardRefetchingAppsList}
              onClick={(): void => {
                void handleHardRefetchAppsList();
              }}
            >
              <RegenerateIcon className="icon-2xs" />
              <FormattedMessage
                id="settings.mcp.apps.refresh"
                defaultMessage="Refresh"
                description="Button label to hard refresh the app list in MCP settings"
              />
            </Button>
          }
        />
        <SettingsGroup.Content>
          <SettingsSurface>
            {legacyRecommendedServers.map((server) => (
              <McpServerRow
                key={server.id}
                leadingSlot={
                  <span className="bg-token-bg-tertiary border-token-border flex size-8 items-center justify-center rounded-md border">
                    {partnerSquareLogos[server.id] ?? null}
                  </span>
                }
                name={server.label}
                iconUrl={server.iconUrl}
                enabled={mcpServers[server.id]?.enabled !== false}
                authStatus={authStatusByServer[server.id]}
                installLabel={
                  isHttpRecommendedMcpServerConfigValue(server.config.value) ? (
                    <FormattedMessage
                      id="settings.mcp.partnerServer.installAndAuthenticate"
                      defaultMessage="Install"
                      description="Button label to install and authenticate a recommended MCP server"
                    />
                  ) : undefined
                }
                subtitle={
                  <FormattedMessage
                    id="settings.mcp.partnerServer.vendor"
                    defaultMessage="by {vendor}"
                    description="Label showing the vendor for a recommended MCP server"
                    values={{ vendor: server.vendor }}
                  />
                }
                description={renderPartnerServerDescription(server.id)}
                installed={Boolean(mcpServers[server.id])}
                statusLoading={
                  hasInstallInProgress
                    ? isInstallingByMcpServerId[server.id] === true
                    : isFetchingMcpServerStatuses &&
                      Boolean(mcpServers[server.id])
                }
                installing={isInstallingByMcpServerId[server.id] === true}
                onRefreshClicked={
                  showInstallRefreshByMcpServerId[server.id] === true
                    ? (): Promise<void> => handleHardRefetchAppsList()
                    : undefined
                }
                refreshing={isHardRefetchingAppsList}
                onInstallClicked={
                  isHttpRecommendedMcpServerConfigValue(server.config.value)
                    ? (): Promise<void> => handleInstallAndAuthenticate(server)
                    : (): Promise<void> => handleInstall(server)
                }
                onEnableClicked={
                  mcpServers[server.id]
                    ? (next): Promise<void> =>
                        handleToggleEnabled(server.id, next)
                    : undefined
                }
                onAuthenticateClicked={
                  mcpServers[server.id]
                    ? (): Promise<void> => handleAuthenticate(server.id)
                    : undefined
                }
                onSettingsClicked={
                  mcpServers[server.id]
                    ? async (): Promise<void> => {
                        setEditingServerKey(server.id);
                        setEditingServerConfig(mcpServers[server.id]);
                      }
                    : undefined
                }
                isReadOnly={serverOrigins[server.id]?.name.type === "project"}
              />
            ))}
            {appsList.map((app) => (
              <McpServerRow
                key={app.id}
                name={app.name}
                iconUrl={app.logoUrl ?? undefined}
                iconUrlDark={app.logoUrlDark ?? undefined}
                reserveIconSlot={true}
                fallbackIcon={
                  <ConnectedAppsIcon className="icon-sm text-token-text-secondary" />
                }
                installLabel={
                  <FormattedMessage
                    id="settings.mcp.app.connect"
                    defaultMessage="Install"
                    description="Button label to connect an app from MCP settings"
                  />
                }
                description={app.description ?? undefined}
                installed={app.isAccessible}
                installing={isAppConnectPending(app.id)}
                installingLabel={
                  <FormattedMessage
                    id="settings.mcp.app.connecting"
                    defaultMessage="Connecting…"
                    description="Button label shown while an app OAuth flow is still finishing in the background"
                  />
                }
                onRefreshClicked={
                  showInstallRefreshByMcpServerId[app.id] === true
                    ? (): Promise<void> => handleHardRefetchAppsList()
                    : undefined
                }
                refreshing={isHardRefetchingAppsList}
                onInstallClicked={async (): Promise<void> => {
                  await handleConnectApp(app);
                }}
                onSettingsClicked={
                  app.isAccessible
                    ? async (): Promise<void> => {
                        handleOpenAppUrl(app.installUrl);
                      }
                    : undefined
                }
                enabled={app.isEnabled}
                onEnableClicked={
                  app.isAccessible
                    ? async (next): Promise<void> => {
                        await handleToggleAppEnabled({
                          appId: app.id,
                          nextEnabled: next,
                        });
                      }
                    : undefined
                }
              />
            ))}
          </SettingsSurface>
        </SettingsGroup.Content>
      </SettingsGroup>
      <AppConnectModal
        app={connectingApp}
        open={connectingApp != null}
        onOpenChange={(nextOpen): void => {
          if (!nextOpen) {
            clearConnectingApp();
          }
        }}
        onOAuthStarted={handleAppConnectOAuthStarted}
        onConnected={() => {
          void handleHardRefetchAppsList();
        }}
      />
    </SettingsContentLayout>
  );
}

function buildServerKey(
  hint: string | null,
  existingKeys: Array<string>,
  currentKey: string | null,
): string {
  const normalized =
    hint
      ?.trim()
      .replace(/\s+/gu, "_")
      .replace(/[^a-zA-Z0-9-_]+/gu, "-")
      .replace(/-+/gu, "-") ?? "";
  const base =
    normalized.length > 0 ? normalized.toLowerCase() : "custom-server";

  const disallowed = existingKeys.filter((key) =>
    currentKey == null ? true : key !== currentKey,
  );

  if (!disallowed.includes(base)) {
    return base;
  }

  let counter = 2;
  let candidate = `${base}-${counter}`;
  while (disallowed.includes(candidate)) {
    counter += 1;
    candidate = `${base}-${counter}`;
  }
  return candidate;
}

function isStreamableHttpConfig(
  config: McpServerConfig,
): config is McpServerConfig & { url: string } {
  return "url" in config;
}

function McpServerRow({
  name,
  iconUrl,
  iconUrlDark,
  reserveIconSlot,
  fallbackIcon,
  leadingSlot,
  subtitle,
  labelTag,
  description,
  className,
  onRefreshClicked,
  refreshing,
  onInstallClicked,
  onManageClicked,
  installed,
  installing,
  installingLabel,
  statusLoading,
  installLabel,
  manageLabel,
  onAuthenticateClicked,
  authStatus,
  onEnableClicked,
  enabled,
  onSettingsClicked,
  isReadOnly,
}: {
  name: string;
  iconUrl?: string;
  iconUrlDark?: string;
  reserveIconSlot?: boolean;
  fallbackIcon?: React.ReactNode;
  leadingSlot?: React.ReactNode;
  subtitle?: React.ReactNode;
  labelTag?: React.ReactNode;
  description?: React.ReactNode;
  className?: string;
  onRefreshClicked?: () => Promise<void>;
  refreshing?: boolean;
  onInstallClicked?: () => Promise<void>;
  onManageClicked?: () => Promise<void>;
  installed: boolean;
  installing?: boolean;
  installingLabel?: React.ReactNode;
  statusLoading?: boolean;
  installLabel?: React.ReactNode;
  manageLabel?: React.ReactNode;
  onAuthenticateClicked?: () => Promise<void>;
  authStatus?: AppServer.v2.McpAuthStatus;
  onEnableClicked?: (next: boolean) => Promise<void>;
  enabled?: boolean;
  onSettingsClicked?: () => Promise<void>;
  isReadOnly?: boolean;
}): React.ReactElement {
  const intl = useIntl();
  const altText = intl.formatMessage(
    {
      id: "settings.mcp.partnerServer.logoAlt",
      defaultMessage: "{label} logo",
      description: "Alt text for a recommended MCP server logo",
    },
    { label: name },
  );
  const showAuthenticateButton =
    !statusLoading &&
    onAuthenticateClicked !== undefined &&
    authStatus &&
    authStatus !== "unsupported" &&
    !(authStatus === "bearerToken" || authStatus === "oAuth");
  const showActions =
    onRefreshClicked !== undefined ||
    (onInstallClicked !== undefined && installed !== true) ||
    (onManageClicked !== undefined && installed === true) ||
    onEnableClicked !== undefined ||
    onSettingsClicked !== undefined ||
    showAuthenticateButton;

  return (
    <SettingsRow
      className={className}
      label={
        <span className="flex items-start gap-3">
          {leadingSlot ? (
            <span className="flex size-8 shrink-0">{leadingSlot}</span>
          ) : null}
          {iconUrl || iconUrlDark || reserveIconSlot ? (
            <span className="bg-token-surface-tertiary flex size-8 shrink-0 items-center justify-center overflow-hidden rounded-md">
              <ConnectorLogo
                alt={altText}
                className="size-full object-contain"
                logoUrl={iconUrl}
                logoDarkUrl={iconUrlDark}
                fallback={
                  fallbackIcon == null ? (
                    <span className="size-full" aria-hidden="true" />
                  ) : (
                    <>{fallbackIcon}</>
                  )
                }
              />
            </span>
          ) : null}
          <span className="flex min-w-0 flex-col gap-0.5 text-sm">
            <span className="flex flex-wrap items-end gap-1">
              <span className="text-token-text-primary font-medium">
                {name}
              </span>
              {labelTag ? labelTag : null}
              {subtitle ? (
                <span className="text-token-text-secondary">{subtitle}</span>
              ) : null}
            </span>
            {description ? (
              <span className="text-token-text-secondary">{description}</span>
            ) : null}
          </span>
        </span>
      }
      description={null}
      control={
        showActions ? (
          <ControlGroup>
            {installing ? (
              <Button
                color="outline"
                className="rounded-sm"
                disabled={onInstallClicked == null}
                onClick={(): void => {
                  void onInstallClicked?.();
                }}
              >
                <Spinner className="icon-xxs" />
                {installingLabel ?? (
                  <FormattedMessage
                    id="settings.mcp.partnerServer.installing"
                    defaultMessage="Installing…"
                    description="Button label shown while a recommended MCP server is being installed"
                  />
                )}
              </Button>
            ) : null}
            {onRefreshClicked && !installed && !installing ? (
              <Button
                color="outline"
                className="rounded-sm"
                loading={refreshing === true}
                onClick={(): void => {
                  void onRefreshClicked();
                }}
              >
                <FormattedMessage
                  id="settings.mcp.apps.refresh"
                  defaultMessage="Refresh"
                  description="Button label to hard refresh the app list in MCP settings"
                />
              </Button>
            ) : null}
            {onInstallClicked && !installed && !installing ? (
              <Button
                color="outline"
                className="rounded-sm"
                // TODO: Re-enable project-config installs once the app server supports project config writes.
                disabled={isReadOnly === true}
                onClick={(): void => {
                  void onInstallClicked();
                }}
              >
                {installLabel ?? (
                  <FormattedMessage
                    id="settings.mcp.partnerServer.install"
                    defaultMessage="Install"
                    description="Button label to install a recommended MCP server"
                  />
                )}
              </Button>
            ) : null}
            {onManageClicked && installed && !installing ? (
              <Button
                color="outline"
                className="rounded-sm"
                onClick={(): void => {
                  void onManageClicked();
                }}
              >
                {manageLabel ?? (
                  <FormattedMessage
                    id="settings.mcp.partnerServer.manage"
                    defaultMessage="Manage"
                    description="Button label to manage an installed recommended app"
                  />
                )}
              </Button>
            ) : null}
            {showAuthenticateButton ? (
              <Button
                color="outline"
                disabled={!!statusLoading}
                className="rounded-sm"
                onClick={(): void => {
                  void onAuthenticateClicked();
                }}
              >
                <FormattedMessage
                  id="settings.mcp.server.login"
                  defaultMessage="Authenticate"
                  description="Button label to authenticate with an MCP server"
                />
              </Button>
            ) : null}
            {onSettingsClicked ? (
              <Button
                color="ghost"
                size="toolbar"
                uniform
                // TODO: Re-enable project-config edits once the app server supports project config writes.
                disabled={isReadOnly === true}
                onClick={(): void => {
                  void onSettingsClicked();
                }}
                aria-label={intl.formatMessage({
                  id: "settings.mcp.server.settings",
                  defaultMessage: "Settings",
                  description: "Button label to view MCP server settings",
                })}
              >
                <SettingsCogIcon className="icon-xs" />
              </Button>
            ) : null}
            {onEnableClicked ? (
              <Toggle
                // TODO: Re-enable project-config toggles once the app server supports project config writes.
                disabled={statusLoading === true || isReadOnly === true}
                checked={enabled === true}
                onChange={(next): void => {
                  void onEnableClicked(next);
                }}
                ariaLabel={intl.formatMessage({
                  id: "settings.mcp.server.enable",
                  defaultMessage: "Enable",
                  description: "Toggle to enable an MCP server",
                })}
              />
            ) : null}
          </ControlGroup>
        ) : null
      }
    />
  );
}

function AddServerButton({
  onClick,
}: {
  onClick?: () => void;
}): React.ReactElement {
  return (
    <Button
      color="ghost"
      size="toolbar"
      onClick={(): void => {
        onClick?.();
      }}
    >
      <PlusIcon className="icon-2xs" />
      <FormattedMessage
        id="settings.mcp.addServer"
        defaultMessage="Add server"
        description="Button to add a new MCP server"
      />
    </Button>
  );
}

function renderPartnerServerDescription(
  id: RecommendedMcpServerId,
): React.ReactElement {
  switch (id) {
    case "linear": {
      return (
        <FormattedMessage
          id="settings.mcp.partnerServer.description.linear"
          defaultMessage="Integrate with Linear's issue tracking and project management"
          description="Description for the Linear MCP server"
        />
      );
    }
    case "notion": {
      return (
        <FormattedMessage
          id="settings.mcp.partnerServer.description.notion"
          defaultMessage="Read docs, update pages, manage tasks"
          description="Description for the Notion MCP server"
        />
      );
    }
    case "figma": {
      return (
        <FormattedMessage
          id="settings.mcp.partnerServer.description.figma"
          defaultMessage="Generate better code by bringing in full Figma context"
          description="Description for the Figma MCP server"
        />
      );
    }
    case "github": {
      return (
        <FormattedMessage
          id="settings.mcp.partnerServer.description.github"
          defaultMessage="Integrate with GitHub APIs to automate workflows and extract data"
          description="Description for the GitHub MCP server"
        />
      );
    }
    case "playwright": {
      return (
        <FormattedMessage
          id="settings.mcp.partnerServer.description.playwright"
          defaultMessage="Integrate browser automation to implement design and test UI."
          description="Description for the Playwright MCP server"
        />
      );
    }
  }
}
